import { useEffect, useState } from 'react';

export function Online() {
  const [on, setOn] = useState(true);
  useEffect(() => {
    const id = setInterval(() => setOn((o) => !o), 5000);
    return () => clearInterval(id);
  }, []);
  return <span>{on ? 'up' : 'flaky'}</span>;
}

